const item = $input.first();
const inputDate = item.json.formattedDate.trim();   // "22/04/2025"

// --- 1. Parsear la fecha DD/MM/YYYY -----------------------------
const [day, month, year] = inputDate.split('/').map(Number); // → [22, 4, 2025]

// --- 2. Construir un Date y sumarle 1 día -----------------------
let base = new Date(year, month - 1, day);          // mes = 0-based
base.setDate(base.getDate() + 1);                   // +1 día

// --- 3. Helper para devolver ISO sin zona horaria --------------
const toISO = (d, hour) => {
  // Creamos un Date en UTC para la hora pedida
  const utc = new Date(Date.UTC(
    d.getFullYear(),
    d.getMonth(),
    d.getDate(),
    hour, 0, 0
  ));
  return utc.toISOString().slice(0, 19);            // YYYY-MM-DDTHH:MM:SS
};

// --- 4. Guardar resultados --------------------------------------
item.json.startDate = toISO(base, 8);   // 08:00:00
item.json.endDate   = toISO(base, 21);  // 21:00:00

return [item];

const results = [];

for (const item of $input.all()) {
    const summary = item?.json?.summary ?? "";
    const description = item?.json?.description ?? "";

    const text = typeof summary === "string" ? summary : "";
    const descText = typeof description === "string" ? description : "";

    const servicio = text.match(/Cita:\s*(.*?)\s*id_servicio/i)?.[1] || "";
    const tiempo = text.match(/Duracion estimada:\s*([0-9]+ ?minutos)/i)?.[1] || "";
    const nombre = text.match(/Para\s+(.*?)\s+[0-9]+@/i)?.[1] || "";
    const numero = text.match(/([0-9]{10,})@s\.whatsapp\.net/i)?.[1] || "";

    // ✅ ahora se llama recomendaciones
    const recomendaciones = descText;

    // Extraer hora desde item.json.start.dateTime
    let horaEntrada = "";
    const startStr = item?.json?.start?.dateTime ?? item?.json?.startDateTime ?? "";

    if (typeof startStr === "string" && startStr.includes("T")) {
        const afterT = startStr.split("T")[1] || "";
        const m = afterT.match(/^(\d{2}:\d{2})/);
        if (m) {
            horaEntrada = `${m[1]} hs`;
        }
    }

    const isEmpty =
        !servicio &&
        !tiempo &&
        !nombre &&
        !numero &&
        !recomendaciones;

    if (!isEmpty) {
        results.push({
            json: {
                id: item.json.id,
                servicio,
                tiempo,
                nombre,
                numero,
                horaEntrada,
                recomendaciones  
            }
        });
    }
}

return results;

